SELECT inq_id AS inqId, user_id AS userId, inq_title AS inqTitle, inq_category AS inqCategory, inq_anonym AS inqAnonym, inq_content AS inqContent, inq_pwd AS inqPwd, inq_reply AS inqReply, inq_attach_file_1 AS inqAttachFile1, inq_attach_file_2 AS inqAttachFile2, inq_attach_file_3 AS inqAttachFile3, inq_attach_file_4 AS inqAttachFile4, inq_attach_file_5 AS inqAttachFile5, inq_status AS inqStatus, inq_create_at AS inqCreateAt, inq_update_at AS inqUpdateAt, inq_check AS inqCheck FROM t_inquire WHERE 1=1
AND inq_category = #{category}
AND ${keywordType} LIKE CONCAT('%', #{keyword}, '%')
AND DATE(inq_create_at) = #{createAt}
ORDER BY inq_create_at DESC LIMIT #{limit} OFFSET #{offset}

